   103|export type DeveloperExecutionGuardResult = {
   104|  ok: boolean;
   105|  violations: string[];
   106|  hasAllSections: boolean;
   107|  hasRawCommandOutput: boolean;
   108|};
   109|
   110|/** Raw command output looks like `$ <cmd> ... exit code: N`. */
   111|export function hasRawCommandOutput(answer: string): boolean {
   112|  const text = answer ?? '';
   113|  const hasCommandLine = /^\s*\$\s+\S+/m.test(text);
   114|  const hasExitCode = /\bexit\s+code:\s*\S+/i.test(text) || /→\s*exit\s+\S+/i.test(text);
   115|  return hasCommandLine && hasExitCode;
   116|}
   117|
   118|/** A positive "verified" claim (not the allowed "NOT VERIFIED — ..." line). */
   119|export function claimsVerified(answer: string): boolean {
   120|  const text = (answer ?? '').toLowerCase();
   121|  // Strip the explicit honest negatives so they never count as a claim.
   122|  const stripped = text
   123|    .replace(/not\s+verified[^\n]*/g, '')
   124|    .replace(/typecheck\s+result:/g, '')
   125|    .replace(/test\s+result:/g, '');
   126|  return /\bverified\b|\bverification\s+passed\b|\ball\s+checks\s+pass(?:ed)?\b/.test(stripped);
   127|}
   128|
   129|/** A "deployed/live in production" claim. */
   130|export function claimsDeployed(answer: string): boolean {
   131|  const text = (answer ?? '').toLowerCase();
   132|  const stripped = text
   133|    .replace(/local\s+only/g, '')
   134|    .replace(/not\s+deployed/g, '')
   135|    .replace(/deploy\s+attempted/g, '');
   136|  return /\bstatus:\s*\n?\s*deployed\b/.test(stripped)
   137|    || /\bdeployed\s+to\s+(?:prod|production|live|render)\b/.test(stripped)
   138|    || /\blive\s+in\s+production\b/.test(stripped);
   139|}
   140|
   141|/** A "done/complete/finished" success claim. */
   142|export function claimsDone(answer: string): boolean {
   143|  const text = (answer ?? '').toLowerCase();
   144|  const stripped = text.replace(/no\s+development\s+was\s+completed/g, '');
   145|  return /\b(?:task\s+)?(?:done|completed|complete|finished|shipped)\b/.test(stripped);
   146|}
   147|
   148|/** True when the answer proves a real file diff (changed paths in PROOF). */
   149|export function hasFileDiffProof(answer: string): boolean {
   150|  const text = answer ?? '';
   151|  if (/NO CODE CHANGED/.test(text)) {
   152|    return false;
   153|  }
   154|  // git diff --stat (applied patch) followed by a " path | summary" line, or a
   155|  // git status --short " M path" line.
   156|  return /git\s+diff\s+--stat[^\n]*\n\s*\S+\s*\|/i.test(text)
   157|    || /git\s+status\s+--short:[\s\S]*\n\s*[AM]\s+\S+/i.test(text);
   158|}
   159|
   160|/** True when a live endpoint / commit proof line is present. */
   161|export function hasDeploymentProof(answer: string): boolean {
   162|  const text = answer ?? '';
   163|  return /\bcommit:\s*[0-9a-f]{6,}/i.test(text)
   164|    || /production\s+\/health:\s*healthy/i.test(text)
   165|    || /changed\s+route:\s*live/i.test(text);
   166|}
   167|
   168|/**
   169| * Validate that a candidate answer is a real developer-execution response and not
   170| * narrative-only or an unproven claim.
   171| */
   172|export function validateDeveloperExecutionAnswer(answer: string): DeveloperExecutionGuardResult {
   173|  const text = answer ?? '';
   174|
   175|  // A guard-blocked answer is a recognised compliant terminal state. It carries
   176|  // the sentinel marker, a BLOCKED status, and NO CODE CHANGED — it makes no
   177|  // success claims, so it passes without re-triggering on the violation reasons
   178|  // it quotes. This guarantees enforcement is idempotent.
   179|  if (text.includes(DEVELOPER_EXECUTION_GUARD_MARKER) && /STATUS:\s*\n?\s*BLOCKED/.test(text) && text.includes('NO CODE CHANGED')) {
   180|    return { ok: true, violations: [], hasAllSections: true, hasRawCommandOutput: false };
   181|  }
   182|
   183|  const violations: string[] = [];
   184|
   185|  const missingSections = REQUIRED_DEVELOPER_SECTIONS.filter((header) => !text.includes(header));
   186|  const hasAllSections = missingSections.length === 0;
   187|  if (!hasAllSections) {
   188|    violations.push(`missing required sections: ${missingSections.join(', ')}`);
   189|  }
   190|
   191|  const rawOutput = hasRawCommandOutput(text);
   192|
   193|  // Banned narrative phrases are only tolerated when real proof accompanies them.
   194|  if (!rawOutput) {
   195|    const lower = text.toLowerCase();
   196|    for (const phrase of BANNED_NARRATIVE_PHRASES) {
   197|      if (lower.includes(phrase)) {
   198|        violations.push(`narrative phrase without proof: "${phrase}"`);
   199|      }
   200|    }
   201|  }
   202|
   203|  if (claimsVerified(text) && !rawOutput) {
   204|    violations.push('claims "verified" without raw command output');
   205|  }
   206|
   207|  if (claimsDeployed(text) && !hasDeploymentProof(text)) {
   208|    violations.push('claims "deployed" without live endpoint / commit proof');
   209|  }
   210|
   211|  if (claimsDone(text) && !hasFileDiffProof(text)) {
   212|    violations.push('claims "done/complete" without a real file diff');
   213|  }
   214|
   215|  return {
   216|    ok: violations.length === 0,
   217|    violations,
   218|    hasAllSections,
   219|    hasRawCommandOutput: rawOutput,
   220|  };
   221|}
