   227| */
   228|export function buildBlockedDeveloperExecutionAnswer(violations: string[]): string {
   229|  const reasons = violations.length > 0 ? violations.map((v) => ` - ${v}`).join('\n') : ' - narrative-only response blocked';
   230|  return [
