   233|    'FILES CHANGED:\nNO CODE CHANGED — no development was completed.',
   234|    'COMMANDS RUN:\nNONE — no commands were executed.',
   235|    'TEST RESULT:\nNOT VERIFIED — tests were not run.',
   236|    'TYPECHECK RESULT:\nNOT VERIFIED — typecheck was not run.',
   237|    'STATUS:\nBLOCKED',
   238|    `PROOF:\nBLOCKED — the generated answer ${DEVELOPER_EXECUTION_GUARD_MARKER}:\n${reasons}`,
   239|  ].join('\n\n');
   240|}
   241|
   242|/**
   243| * Enforce developer-execution mode on a candidate answer. Returns the original
   244| * answer when it passes, otherwise a BLOCKED replacement. Never lets a
   245| * narrative-only / unproven answer reach the owner.
   246| */
   247|export function enforceDeveloperExecutionAnswer(answer: string): {
   248|  answer: string;
   249|  enforced: boolean;
   250|  result: DeveloperExecutionGuardResult;
   251|} {
